mapper.select:
select ri.id, ri.room_number, ri.rent, ai.id as ai_id, ai.name, ai.introduction, ai.district_id, ai.district_name, ai.city_id, ai.city_name, ai.province_id, ai.province_name, ai.address_detail, ai.latitude, ai.longitude, ai.phone, ai.is_release from room_info as ri join apartment_info as ai on ai.id = ri.apartment_id and ai.is_deleted = 0 and ai.is_release = 1
ri.is_deleted = 0 and ri.is_release = 1 and ri.id not in (select room_id from lease_agreement where is_deleted = 0 and status in (2, 5))
and ai.province_id = #{queryVo.provinceId}
and ai.city_id = #{queryVo.cityId}
and ai.district_id = #{queryVo.districtId}
and ri.rent >= #{queryVo.minRent}
and ri.rent <= #{queryVo.maxRent}
and ri.id in(select room_id from room_payment_type where is_deleted=0 and payment_type_id=#{queryVo.paymentTypeId})
order by ri.rent ${queryVo.orderType}
